// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// 2021.04.13 - STRY0099479 - fix issue with 0 duration on template task
	// 07.07.20: Tasker 2.5.0 Patch 1 Hotfix 2 Madrid
	//var taskerNM = new TaskerDisplayValueConfiguration();

	// v2.5.13 | 07.20.2020 | STRY00#####:  Sequential Review
	//---------------------------------------------------------------------------------------------
	var insertTaskerHelper = new TaskerHelpers();
	var initialState = insertTaskerHelper.getInitialState(current);
	current.state = initialState;
	/*
	if(current.assigned_to.nil()){
		current.state = -5;
	}
	if(!current.assigned_to.nil()){
		current.state = 1;
	}
	*/
	//---------------------------------------------------------------------------------------------

	// RJ - STRY0063760 - moved the setting of current.numberperprimaryassignee into a different if statement.
	// This value should be set when the Primary Assignee is set, not when teh Assigned Member is set.
	// STRY0051139 - Primary Assignee no longer is used to set the number.
	// this could have led to duplicates and to numbers changing on a Primary Assignee change
	//if(!current.primary_assignee.nil()){
	//current.numberperprimaryassignee = taskerNM.padObjNumber(taskerNM.getNextTaskerNumberperPrimaryAssignee(current.primary_assignee),5);
	//}

	// STRY0072379
	var now = new GlideDateTime();
	// STRY0099479
	if(current.source_definition.nil()){
		if(now > current.suspense_date && current.suspense_date != ''){
			if(gs.getProperty('x_153465_discovert.Suspense Dates and Expected Start Dates must be in the future') == 'true'){
				gs.addErrorMessage('The suspense date must be in the future.');
				current.setAbortAction(true);
			} else {
				current.work_notes = 'Task created with a suspense date in the past.';
			}
		}
	}

	// RAJ 2020.02.11  STRY0059160
	// if Parent is empty, then set the Top Task Refernece equal to this Task so it gets passed down the entire tree
	// Set the Top Task Number (used in DocInt to get documents based on task number) to the display value for the top task
	if(!current.parent){
		current.u_top_task = current.sys_id;
	}
	else{
		// RAJ 2020.02.11  STRY0059160
		// when creating a sub task, set the Top Task Refernece equal to the parent task's Top Task so it gets passed down the entire tree
		// Set the Top Task Number (used in DocInt to get documents based on task number) to the display value for the top task
		current.u_top_task = current.parent.u_top_task; 
		current.u_task_tree = current.parent.u_task_tree;
		//  TISA - STRY0063859 - if the parent task is related to a table and row, relate the child to a table and row
		current.table_name = current.parent.table_name;
		current.table_sys_id = current.parent.table_sys_id;
	}

	// STRY0051139 - allow customer to use the script associated with this to set key values in the system
	// ships with the defalut setting current.taskernumber = current.u_task_tree.u_shared_task_label + '-' + current.getDisplayValue('primary_assignee');
	// STRY0066883 - this does not work.  The task tree has not been created yet.  So, this number did NOT get set right
	//current.taskernumber = taskerNM.setTaskerNumber(current);

})(current, previous);
